SELECT /* @SQLID=SUB020301_02-01#Sql001 */ COUNT(*) OVER() AS totalCount, A.BROKER_CODE AS brokerCode, A.BROKER_BRANCH_CODE AS brokerageBranchCode, A.BROKER_NAME AS brokerName, A.BROKER_CHARGE_CODE AS empCode, A.BROKER_CHARGE_NAME AS brokerChargeName, A.CUSTOMER_ATTRIBUTE_NAME AS courseName, A.BUTEN_CODE AS butenCode, A.ACCOUNT_NUMBER AS accountNumber, A.NAME_KANJI AS customerName, A.BRAND_CODE AS brandCode, A.BRAND_NAME AS brandName, A.EXEC_BASE_BALANCE AS contractStandardDeposit, A.DISPLAY_LAST_TRADE_DATE AS displayLastTradeDate, A.SBI_LAST_TRADE_DATE AS sbiLastTradeDate, B.BRANCH_NAME AS brokerBranchName, C.NAME_KANA AS customerNameKana FROM V_BALANCE A LEFT JOIN MEDIATE_BRANCH B ON A.BROKER_CODE = B.BROKER_CODE AND A.BROKER_BRANCH_CODE ＝ B.BROKER_BRANCH_CODE AND B.DELETE_FLG = '0' INNER JOIN MEDIATE_USER_ATTRIBUTE_INFO C ON A.BUTEN_CODE = C.BUTEN_CODE AND A.ACCOUNT_NUMBER = C.ACCOUNT_NUMBER WHERE A.DATE_YMD = #{req.dateYmd} AND A.PRODUT_CD ＝ '02' AND ( (A.SBI_LAST_TRADE_DATE IS NULL AND A.DISPLAY_LAST_TRADE_DATE <= #{req.designatedDate}) OR (A.SBI_LAST_TRADE_DATE IS NOT NULL AND ( (A.DISPLAY_LAST_TRADE_DATE > A.SBI_LAST_TRADE_DATE AND A.SBI_LAST_TRADE_DATE <= #{req.designatedDate}) OR (A.DISPLAY_LAST_TRADE_DATE <= A.SBI_LAST_TRADE_DATE AND A.DISPLAY_LAST_TRADE_DATE <= #{req.designatedDate})) ) )
AND (A.BROKER_CODE IN
) OR A.BROKER_CODE IN(
,
#{brokerCharge.brokerCode}
)
AND ((A.BROKER_CODE, A.BROKER_CHARGE_CODE) IN
) OR (A.BROKER_CODE, A.BROKER_CHARGE_CODE) IN(
,
(#{brokerCharge.brokerCode}, #{brokerCharge.empCode})
)
AND A.BROKER_CODE IN
#{brokerCode}
AND A.BROKER_CODE NOT IN
#{brokerCode}
AND A.BROKER_BRANCH_CODE = #{req.branchCode}
AND A.BROKER_CHARGE_CODE = #{req.empCode}
AND A.BUTEN_CODE = #{req.butenCode}
AND A.ACCOUNT_NUMBER = TO_NUMBER(#{req.accountNumber})
AND (A.NAME_KANJI = #{req.customerNameKanjiKana} OR C.NAME_KANA = #{req.customerNameKanjiKana})
AND (A.NAME_KANJI like CONCAT(#{req.customerNameKanjiKana}, '%') OR C.NAME_KANA like CONCAT(#{req.customerNameKanjiKana}, '%'))
AND (A.NAME_KANJI like CONCAT(CONCAT('%', #{req.customerNameKanjiKana}), '%') OR C.NAME_KANA like CONCAT(CONCAT('%', #{req.customerNameKanjiKana}), '%'))
AND A.CUSTOMER_ATTRIBUTE IN
#{course}
ORDER BY A.BROKER_CODE,A.BROKER_CHARGE_CODE,A.BUTEN_CODE,A.ACCOUNT_NUMBER,A.BRAND_CODE FETCH FIRST 5000 ROWS ONLY
